package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Reptil; public class Tartaruga extends Reptil implements Corrida, Nado { public Tartaruga(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " faz sons baixos e discretos."); } public void comer() { System.out.println(getNome() + " está comendo folhas."); } public void correr() { System.out.println(getNome() + " está se locomovendo lentamente em terra."); } public void nadar() { System.out.println(getNome() + " está nadando calmamente."); } }
